// File: src/pages/KhaiBaoCoSo.js (PHIÊN BẢN KIỂM TRA - BƯỚC 2)
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './KhaiBaoCoSo.css';

function KhaiBaoCoSo() {
    console.log("Đang render KhaiBaoCoSo - Bước 2");
    
    const navigate = useNavigate();

    // Thêm lại state
    const [formData, setFormData] = useState({
        loaiCoSoDangKy: '',
        // Thêm các trường khác sau khi xác nhận bước này hoạt động
    });

    // Thêm lại useEffect để kiểm tra token
    useEffect(() => {
        const token = localStorage.getItem('token');
        if (!token) {
            navigate('/login');
        }
    }, [navigate]);

    // Thêm lại hàm handleChange đơn giản
    const handleChange = (e) => {
        const { name, value } = e.target;
        console.log(`handleChange được gọi: name='${name}', value='${value}'`);
        setFormData(prevData => ({
            ...prevData,
            [name]: value
        }));
    };

    return (
        <div className="khai-bao-container">
            <h2>Đăng ký cơ sở (Bước 2)</h2>
            
            <form className="khai-bao-form">
                <section className="khai-bao-section">
                    <h3>Loại cơ sở đăng ký</h3>
                    <div className="form-group">
                        <label htmlFor="loaiCoSoDangKy">Chọn loại cơ sở đăng ký:</label>
                        <select id="loaiCoSoDangKy" name="loaiCoSoDangKy" value={formData.loaiCoSoDangKy} onChange={handleChange} required>
                            <option value="">-- Chọn loại --</option>
                            <option value="Đăng ký cơ sở gây nuôi">Cơ sở gây nuôi (Động vật/Thực vật)</option>
                            <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Cơ sở kinh doanh, chế biến gỗ</option>
                        </select>
                    </div>
                </section>

                <hr />
                <p>Giá trị đang được chọn: <strong>{formData.loaiCoSoDangKy || 'Chưa chọn'}</strong></p>

                {/* Tạm thời chưa thêm các khối hiển thị có điều kiện */}

            </form>
        </div>
    );
}

export default KhaiBaoCoSo;
